    employee_id: '3456',
    first_name: 'Derek',
    last_name: 'Pascarella',
    email: 'derek.pascarella@resolve.io',
    active: true
  },
  {
    phone_number: '+14084318627',
    employee_id: '4567',
    first_name: 'Alex',
    last_name: 'Yupanqui',
    email: 'alex.yupanqui@resolve.io',
    active: true
  }
];

const phone = $json.phone_number;

const match = knownCallers.find(
  c => c.phone_number === phone && c.active
);

if (match) {
  return {
    json: {
      recognized: true,
      first_name: match.first_name,
      last_name: match.last_name,
      employee_id: match.employee_id,
      email: match.email
    }
  };
}

return {
  json: {
    recognized: false
  }
};
